features.snippet:
sv.reg @res_reg : !hw.inout<i17>
sv.alwaysff(posedge %clk) {
  sv.case casez %sel : i3
  case b000: { sv.bpassign %res_reg, %c1 : i17 }
  default: { sv.bpassign %res_reg, %c2 : i17 }
  %v = sv.read_inout %res_reg : !hw.inout<i17>
  %e = comb.extract %v from 0 : (i17) -> i8
  sv.passign %res_reg, %e : i8
}

hw.module @m(%clk : i1, %sel : i3) attributes {circt.loweringOptions = "disallowLocalVariables"} {
  sv.alwaysff(posedge %clk) {
    sv.case casez %sel : i3 case b000: { sv.bpassign %r, %c : i32 }
  }
}
